SET transaction_timeout = 0;
SET check_function_bodies = false;

-- NOTE: the metrics_schema rows inserted into public.exercises_cardio at the
-- bottom of this file mirror migration 1790000410000_exercise_metrics_schema;
-- keep them in sync. In particular, avg_hr_bpm must use "x-format":"average"
-- so it is averaged (not summed) across entries in a session.
--
-- The migration's INSERT also runs as part of `nhost up`, but it joins on
-- `exercises.slug` and matches zero rows on a fresh DB (migrations run before
-- seeds). The seed below is what actually populates exercises_cardio on local
-- dev; the migration's backfill is for applying the migration to an
-- already-seeded production DB.



-- Strength sidecar rows: one per non-cardio exercise. The base `exercises`
-- INSERT above carries only shared columns; double_weight/force/mechanic
-- live here instead.

-- Cardio metrics schemas. See the NOTE at the top of this file for why the
-- seed and the migration both carry these inserts.

SELECT id, $$
{
  "type": "object",
  "additionalProperties": false,
  "properties": {
    "distance_km":   { "type": "number",  "minimum": 0, "exclusiveMaximum": 1000,
                       "x-label": "Distance", "x-unit": "km",   "x-format": "decimal",          "x-order": 1 },
    "duration_s":    { "type": "integer", "minimum": 0, "maximum": 86400,
                       "x-label": "Duration", "x-unit": "",     "x-format": "duration_seconds", "x-order": 2 },
    "calories_kcal": { "type": "integer", "minimum": 0, "maximum": 10000,
                       "x-label": "Calories", "x-unit": "kcal", "x-format": "integer",          "x-order": 3 },
    "avg_hr_bpm":    { "type": "integer", "minimum": 0, "maximum": 300,
                       "x-label": "Avg HR",   "x-unit": "bpm",  "x-format": "average",          "x-order": 4 }
  },
  "required": ["duration_s"]
}
$$::jsonb
FROM public.exercises
WHERE slug IN (
  'Bicycling',
  'Bicycling_Stationary',
  'Elliptical_Trainer',
  'Jogging_Treadmill',
  'Recumbent_Bike',
  'Rowing_Stationary',
  'Running_Treadmill',
  'Trail_Running_Walking',
  'Walking_Treadmill',
  'Skating'
);

SELECT id, $$
{
  "type": "object",
  "additionalProperties": false,
  "properties": {
    "duration_s":    { "type": "integer", "minimum": 0, "maximum": 86400,
                       "x-label": "Duration", "x-unit": "",     "x-format": "duration_seconds", "x-order": 1 },
    "floors":        { "type": "integer", "minimum": 0, "maximum": 10000,
                       "x-label": "Floors",   "x-unit": "",     "x-format": "integer",          "x-order": 2 },
    "steps":         { "type": "integer", "minimum": 0, "maximum": 1000000,
                       "x-label": "Steps",    "x-unit": "",     "x-format": "integer",          "x-order": 3 },
    "calories_kcal": { "type": "integer", "minimum": 0, "maximum": 10000,
                       "x-label": "Calories", "x-unit": "kcal", "x-format": "integer",          "x-order": 4 }
  },
  "required": ["duration_s"]
}
$$::jsonb
FROM public.exercises
WHERE slug IN (
  'Stairmaster',
  'Step_Mill'
);

SELECT id, $$
{
  "type": "object",
  "additionalProperties": false,
  "properties": {
    "duration_s":    { "type": "integer", "minimum": 0,
                       "x-label": "Duration", "x-unit": "",     "x-format": "duration_seconds", "x-order": 1 },
    "rounds":        { "type": "integer", "minimum": 0, "maximum": 100,
                       "x-label": "Rounds",   "x-unit": "",     "x-format": "integer",          "x-order": 2 },
    "calories_kcal": { "type": "integer", "minimum": 0, "maximum": 10000,
                       "x-label": "Calories", "x-unit": "kcal", "x-format": "integer",          "x-order": 3 }
  },
  "required": ["duration_s"]
}
$$::jsonb
FROM public.exercises
WHERE slug IN (
  'Rope_Jumping',
  'Prowler_Sprint'
);

